}

const DATA = [40, 55, 45, 70, 60, 82, 75, 91, 85, 95, 88, 100];
const MONTHS = ["Jan","Feb","Mär","Apr","Mai","Jun","Jul","Aug","Sep","Okt","Nov","Dez"];

export default function ChartLineTrend01() {
  const W = 600;
  const H = 120;
  const max = Math.max(...DATA);
  const pts = DATA.map((v, i) => `${(i / (DATA.length - 1)) * W},${H - (v / max) * H}`).join(" ");
  return (
    <section className="rounded-2xl border border-slate-200 bg-white p-6 dark:border-slate-800 dark:bg-slate-900">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold text-slate-900 dark:text-white">Jahresverlauf</h3>
        <span className="rounded-full bg-emerald-100 px-2 py-0.5 text-xs font-semibold text-emerald-700">+150% YoY</span>
      </div>
      <div className="mt-4 overflow-hidden">
        <svg viewBox={`0 0 ${W} ${H + 10}`} className="w-full">
          <defs>
            <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#6366F1" stopOpacity="0.4" />
              <stop offset="100%" stopColor="#6366F1" stopOpacity="0" />
            </linearGradient>
          </defs>
          <polygon points={`0,${H} ${pts} ${W},${H}`} fill="url(#lineGrad)" />
          <polyline points={pts} fill="none" stroke="#6366F1" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
      </div>
      <div className="mt-2 flex justify-between text-[10px] text-slate-400">
        {MONTHS.map((m) => <span key={m}>{m}</span>)}
      </div>
    </section>
  );
}

const SEGMENTS = [
  { label: "Direkt", value: 38, color: "#7C3AED" },
  { label: "Organisch", value: 27, color: "#06B6D4" },
  { label: "Social", value: 20, color: "#F59E0B" },
  { label: "Referral", value: 15, color: "#10B981" },
];

export default function ChartDonut01() {
  const total = SEGMENTS.reduce((s, seg) => s + seg.value, 0);
  const R = 40;
  const cx = 60, cy = 60;
  const circumference = 2 * Math.PI * R;
  let offset = 0;

  return (
    <section className="rounded-2xl border border-slate-200 bg-white p-6 dark:border-slate-800 dark:bg-slate-900">
      <h3 className="text-sm font-semibold text-slate-900 dark:text-white">Traffic-Quellen</h3>
      <div className="mt-4 flex items-center gap-8">
        <svg viewBox="0 0 120 120" className="w-32 shrink-0" style={{ transform: "rotate(-90deg)" }}>
          {SEGMENTS.map((seg) => {
            const dash = (seg.value / total) * circumference;
            const gap = circumference - dash;
            const el = (
              <circle
                key={seg.label}
                cx={cx} cy={cy} r={R}
                fill="none"
                stroke={seg.color}
                strokeWidth={18}
                strokeDasharray={`${dash} ${gap}`}
                strokeDashoffset={-offset}
              />
            );
            offset += dash;
            return el;
          })}
        </svg>
        <ul className="flex-1 space-y-2">
          {SEGMENTS.map((seg) => (
            <li key={seg.label} className="flex items-center justify-between text-sm">
              <div className="flex items-center gap-2">
                <span className="h-2.5 w-2.5 rounded-full" style={{ background: seg.color }} />
                <span className="text-slate-600 dark:text-slate-300">{seg.label}</span>
              </div>
              <span className="font-semibold text-slate-900 dark:text-white">{seg.value}%</span>
            </li>
          ))}
        </ul>
      </div>
    </section>
  );
}

