];

function Sparkline({ data, up }: { data: number[]; up: boolean }) {
  const max = Math.max(...data);
  const min = Math.min(...data);
  const W = 80, H = 28;
  const pts = data.map((v, i) => `${(i / (data.length - 1)) * W},${H - ((v - min) / (max - min || 1)) * H}`).join(" ");
  return (
    <svg viewBox={`0 0 ${W} ${H}`} className="w-20 h-7">
      <polyline points={pts} fill="none" stroke={up ? "#10B981" : "#F43F5E"} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

export default function ChartSparklineCards01() {
  return (
    <section className="grid gap-4 sm:grid-cols-3">
      {METRICS.map((m) => (
        <article key={m.label} className="rounded-2xl border border-slate-200 bg-white p-5 dark:border-slate-800 dark:bg-slate-900">
          <p className="text-xs text-slate-500">{m.label}</p>
          <div className="mt-2 flex items-end justify-between">
            <div>
              <p className="text-2xl font-bold text-slate-900 dark:text-white">{m.value}</p>
              <p className={`text-xs font-semibold ${m.up ? "text-emerald-500" : "text-rose-500"}`}>{m.change} vs. Vormonat</p>
            </div>
            <Sparkline data={m.data} up={m.up} />
          </div>
        </article>
      ))}
    </section>
  );
}

